def read_csv(filepath: str) -> list[dict]:
    """Read a CSV file and return a list of dicts."""
    path = Path(filepath)
    if not path.exists():
        raise FileNotFoundError(f"File not found: {filepath}")
    with open(path, 'r', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        return list(reader)
